import{_ as a,o as t,c as i,a1 as n}from"./chunks/framework.BwbI10pK.js";const m=JSON.parse('{"title":"Career System","description":"","frontmatter":{},"headers":[],"relativePath":"en/career/index.md","filePath":"en/career/index.md"}'),r={name:"en/career/index.md"};function o(l,e,c,s,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="career-system" tabindex="-1">Career System <a class="header-anchor" href="#career-system" aria-label="Permalink to &quot;Career System&quot;">​</a></h1><blockquote><p>Subtitle: From capability model to technical influence, build a quantifiable growth path rather than vague advice.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>The growth of a frontend engineer is not automatic after writing code for a few more years. It requires actively building a capability model, planning a technical path, and accumulating technical influence. This module does not offer vague advice like &quot;read more source code&quot; or &quot;solve more problems.&quot; Instead, it decomposes growth into quantifiable capability dimensions, executable growth ladders, and observable influence signals.</p><p>Whether you are a junior engineer just starting out or a mid-to-senior engineer aiming to break through to architect, you can find the corresponding advancement framework in this module.</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Capability model</strong>: T-shaped vs π-shaped talent, quantified dimensions of technical depth and breadth, and capability radar charts.</li><li><strong>Growth path</strong>: Key leap points and bottlenecks from junior → intermediate → senior → staff → architect.</li><li><strong>Technical influence</strong>: Layered progression from code contributions, technical sharing, open-source participation, technical decision-making, to team enablement.</li><li><strong>Career decisions</strong>: Technical track vs management track, big tech vs startup, and timing judgment for job changes.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/career/capability-model">Frontend Engineer Capability Model</a> — Quantify capability dimensions to avoid the feeling of &quot;knowing a little about everything.&quot;</li><li><a href="/en/career/growth-path">Technical Growth Path</a> — Key capabilities, typical bottlenecks, and breakthrough methods at each level.</li><li><a href="/en/career/technical-influence">Building Technical Influence</a> — Five levels of influence and observable signals.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Junior and intermediate frontend engineers who want to clarify the next stage of growth.</li><li>Senior and staff engineers who want to break through to architect or technical lead.</li><li>Engineering managers who need to build team capability assessment and cultivation systems.</li></ul>',11)])])}const g=a(r,[["render",o]]);export{m as __pageData,g as default};
